package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost;

import java.util.Map;
import java.util.OptionalDouble;
import java.util.Set;

public record SketchEvidence(VariableSetKey key, DistributionSketch sketch, double rows, double distinctRows,
		EvidenceQuality quality, String provenance, boolean current, boolean stale) {

	public SketchEvidence(VariableSetKey key, DistributionSketch sketch, double rows, double distinctRows,
			EvidenceQuality quality, String provenance) {
		this(key, sketch, rows, distinctRows, quality, provenance, true, false);
	}

	public SketchEvidence {
		if (key == null) {
			throw new IllegalArgumentException("key must not be null");
		}
		rows = finiteNonNegative(rows);
		distinctRows = finiteNonNegative(distinctRows);
		if (distinctRows == 0.0d && sketch != null) {
			distinctRows = finiteNonNegative(sketch.distinctRows());
		}
		quality = quality == null ? EvidenceQuality.HEURISTIC : quality;
		provenance = provenance == null || provenance.isBlank() ? "unknown" : provenance;
	}

	public static SketchEvidence of(Set<String> names, DistributionSketch sketch, double rows, double distinctRows,
			EvidenceQuality quality, String provenance) {
		return new SketchEvidence(VariableSetKey.of(names), sketch, rows, distinctRows, quality, provenance);
	}

	public SketchEvidence rebaseRows(double rows, String provenance) {
		return new SketchEvidence(key, sketch, rows, Math.min(distinctRows, Math.max(1.0d, rows)), quality, provenance,
				current, stale);
	}

	public SketchEvidence asCurrent(String provenance) {
		return new SketchEvidence(key, sketch, rows, distinctRows, quality, provenance, true, false);
	}

	public SketchEvidence asSupporting(String provenance) {
		return new SketchEvidence(key, sketch, rows, distinctRows, quality, provenance, false, stale);
	}

	public SketchEvidence asStaleSupporting(String provenance) {
		return new SketchEvidence(key, sketch, rows, distinctRows, quality, provenance, false, true);
	}

	public EvidenceScalar estimateInnerProduct(SketchEvidence other) {
		if (other == null || sketch == null || other.sketch == null) {
			return EvidenceScalar.unusable("missing-sketch-evidence");
		}
		OptionalDouble delegated = delegatedInnerProduct(other.sketch);
		if (usable(delegated)) {
			return EvidenceScalar.of(delegated.getAsDouble(), composedQuality(other), "sketch-inner-product");
		}
		OptionalDouble fallback = scalarFallback(other);
		if (usable(fallback)) {
			return new EvidenceScalar(fallback.getAsDouble(), EvidenceQuality.SCALAR_FALLBACK,
					"sketch-scalar-fallback", Map.of());
		}
		return EvidenceScalar.unusable("unusable-sketch-evidence");
	}

	private OptionalDouble delegatedInnerProduct(DistributionSketch otherSketch) {
		return sketch.highQualityInnerProduct(otherSketch);
	}

	private EvidenceQuality composedQuality(SketchEvidence other) {
		EvidenceQuality combined = quality.min(other.quality);
		return combined == EvidenceQuality.SCALAR_FALLBACK || combined == EvidenceQuality.HEURISTIC
				? EvidenceQuality.COMPOSED_SKETCH
				: combined;
	}

	private OptionalDouble scalarFallback(SketchEvidence other) {
		if (rows <= 0.0d || other.rows <= 0.0d) {
			return OptionalDouble.empty();
		}
		double denominator = Math.max(1.0d, Math.max(distinctRows, other.distinctRows));
		double value = (rows * other.rows) / denominator;
		return Double.isFinite(value) && value >= 0.0d ? OptionalDouble.of(value) : OptionalDouble.empty();
	}

	private static boolean usable(OptionalDouble rows) {
		return rows.isPresent() && Double.isFinite(rows.getAsDouble()) && rows.getAsDouble() >= 0.0d;
	}

	private static double finiteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d ? value : 0.0d;
	}
}
